1	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
2	import { MemoryRouter } from "react-router-dom";
3	import { SessionProvider } from "@/features/session/context";
4	import { routerFuture } from "@/app/routerFuture";
5	import { render, type RenderOptions } from "@testing-library/react";
6	import type { ReactElement, ReactNode } from "react";
7	
8	function createTestQueryClient() {
9	  return new QueryClient({
10	    defaultOptions: {
11	      queries: { retry: false, gcTime: 0 },
12	      mutations: { retry: false },
13	    },
14	  });
15	}
16	
17	function TestProviders({
18	  children,
19	  initialEntries,
20	}: {
21	  children: ReactNode;
22	  initialEntries?: string[];
23	}) {
24	  const qc = createTestQueryClient();
25	  return (
26	    <QueryClientProvider client={qc}>
27	      <SessionProvider>
28	        <MemoryRouter future={routerFuture} initialEntries={initialEntries}>
29	          {children}
30	        </MemoryRouter>
31	      </SessionProvider>
32	    </QueryClientProvider>
33	  );
34	}
35	
36	export function renderWithProviders(
37	  ui: ReactElement,
38	  options?: Omit<RenderOptions, "wrapper"> & { route?: string; initialEntries?: string[] },
39	) {
40	  const { route, initialEntries, ...renderOptions } = options ?? {};
41	
42	  function Wrapper({ children }: { children: ReactNode }) {
43	    return (
44	      <TestProviders initialEntries={initialEntries ?? (route ? [route] : undefined)}>
45	        {children}
46	      </TestProviders>
47	    );
48	  }
49	
50	  return render(ui, { wrapper: Wrapper, ...renderOptions });
51	}
52

1	import { createContext, useContext, useState, useCallback, type ReactNode } from "react";
2	import type { Session } from "@/lib/api/types";
3	
4	const STORAGE_KEY = "bayes-session";
5	
6	function loadSession(): Session {
7	  try {
8	    const raw = localStorage.getItem(STORAGE_KEY);
9	    if (raw) {
10	      const parsed = JSON.parse(raw) as Session;
11	      return { accountId: parsed.accountId ?? "", agentId: parsed.agentId ?? "" };
12	    }
13	  } catch {
14	    // ignore corrupt storage
15	  }
16	  return { accountId: "", agentId: "" };
17	}
18	
19	function saveSession(session: Session): void {
20	  localStorage.setItem(STORAGE_KEY, JSON.stringify(session));
21	}
22	
23	interface SessionContextValue {
24	  session: Session;
25	  setAccountId: (id: string) => void;
26	  setAgentId: (id: string) => void;
27	  isConfigured: boolean;
28	}
29	
30	const SessionContext = createContext<SessionContextValue | null>(null);
31	
32	export function SessionProvider({ children }: { children: ReactNode }) {
33	  const [session, setSession] = useState<Session>(loadSession);
34	
35	  const setAccountId = useCallback((accountId: string) => {
36	    setSession((prev) => {
37	      const next = { ...prev, accountId };
38	      saveSession(next);
39	      return next;
40	    });
41	  }, []);
42	
43	  const setAgentId = useCallback((agentId: string) => {
44	    setSession((prev) => {
45	      const next = { ...prev, agentId };
46	      saveSession(next);
47	      return next;
48	    });
49	  }, []);
50	
51	  return (
52	    <SessionContext.Provider
53	      value={{ session, setAccountId, setAgentId, isConfigured: session.accountId.length > 0 }}
54	    >
55	      {children}
56	    </SessionContext.Provider>
57	  );
58	}
59	
60	export function useSession(): SessionContextValue {
61	  const ctx = useContext(SessionContext);
62	  if (!ctx) throw new Error("useSession must be used within SessionProvider");
63	  return ctx;
64	}
65

